-- create "checkpoints" table
CREATE TABLE "checkpoints" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY (START WITH 55834574848), "create_time" timestamptz NOT NULL, "update_time" timestamptz NOT NULL, "net_worth" numeric(36,18) NOT NULL, "liquidity" numeric(36,18) NOT NULL, "investment" numeric(36,18) NOT NULL, "property" numeric(36,18) NOT NULL, "receivable" numeric(36,18) NOT NULL, "liability" numeric(36,18) NOT NULL, "note" text NULL, "currency_id" bigint NOT NULL, "household_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "checkpoints_currencies_checkpoints" FOREIGN KEY ("currency_id") REFERENCES "currencies" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "checkpoints_households_checkpoints" FOREIGN KEY ("household_id") REFERENCES "households" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- create index "checkpoint_household_id_create_time" to table: "checkpoints"
CREATE INDEX "checkpoint_household_id_create_time" ON "checkpoints" ("household_id", "create_time");
